(self.webpackChunksqlitelearn=self.webpackChunksqlitelearn||[]).push([[5653],{5653:function(n,e,t){"use strict";t.r(e);var a=t(9654);e.default={question:"Each admission costs $50 for patients without insurance, and $10 for patients with insurance. All patients with an even patient_id and first_name between F and R (inclusive), have insurance.\n<br><br>\nGive each patient a 'Yes' if they have insurance, and a 'No' if they don't have insurance. Add up the admission_total cost for each has_insurance group.",solution:"SELECT \nCASE WHEN p.patient_id % 2 = 0 AND p.first_name BETWEEN 'F%' and 'R%' Then \n    'Yes'\nELSE \n    'No' \nEND as has_insurance,\nSUM(CASE WHEN p.patient_id % 2 = 0 AND p.first_name BETWEEN 'F%' and 'R%' Then \n    10\nELSE \n    50 \nEND) as cost_after_insurance\nFROM admissions a \nJOIN patients p ON a.patient_id = p.patient_id\nGROUP BY has_insurance;",expectedOutput:null,usedTables:["patients","admissions"],hints:{keywordsUsed:["SELECT","CASE","JOIN","SUM","GROUP BY"],solutionPortion:"WHEN p.patient_id % 2 = 0 AND p.first_name BETWEEN 'F%' and 'R%' Then "},expectedDBState:null,validator:function(n,e){return a.Z.hashColumns((null==e?void 0:e.values)||[],!1)==a.Z.hashColumns(this.expectedOutput[0].values,!1)},initalize:function(n){this.expectedOutput=n.exec(this.solution),this.expectedDBState=n}}}}]);